using UnityEngine;

/// <summary>
/// Sonar (P5): emite um pulso em área que revela temporariamente objectos
/// marcados com SonarRevealable (paredes falsas, segredos, itens escondidos)
/// dentro de "sonarRadius" da forma, durante "sonarRevealDuration" (P1).
///
/// Activado via PrimaryAbility.Sonar (AbilityRouter.OnAbilityPressed → TryPing).
/// </summary>
public class SonarAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Feedback (opcional)")]
    [Tooltip("Prefab de VFX do pulso (anel a expandir, etc), instanciado no player.")]
    public GameObject pingVfxPrefab;

    public AudioClip pingSound;

    private bool enabledForForm;
    private float radius = 6f;
    private float revealDuration = 4f;
    private float cooldown = 5f;
    private float cooldownTimer;

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && (form.hasSonar || form.primaryAbility == PrimaryAbility.Sonar);
        radius = form != null ? Mathf.Max(1f, form.sonarRadius) : 6f;
        revealDuration = form != null ? Mathf.Max(0.5f, form.sonarRevealDuration) : 4f;
        cooldown = form != null ? Mathf.Max(0f, form.sonarCooldown) : 5f;
    }

    /// <summary>Emite o pulso (AbilityRouter — PrimaryAbility.Sonar).</summary>
    public void TryPing()
    {
        if (!enabledForForm || cooldownTimer > 0f) return;

        cooldownTimer = cooldown;

        if (pingVfxPrefab != null)
            Instantiate(pingVfxPrefab, transform.position, Quaternion.identity);

        if (pingSound != null)
            AudioSource.PlayClipAtPoint(pingSound, transform.position);

        var hits = Physics2D.OverlapCircleAll(transform.position, radius);

        foreach (var hit in hits)
        {
            var revealable = hit.GetComponent<SonarRevealable>();
            if (revealable != null) revealable.Reveal(revealDuration);
        }
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.4f, 0.7f, 1f, 0.5f);
        Gizmos.DrawWireSphere(transform.position, radius > 0f ? radius : 6f);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Instantânea, sem estado persistente — só o cooldown importa para a HUD.
    void IAbility.Activate() => TryPing();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => false;
    public float CooldownDuration => cooldown;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f;

    /// <summary>AnimalsDebugPanel — zera o cooldown do sonar.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
